pageStyles:
* { margin: 0; padding: 0; box-sizing: border-box; }

  @keyframes fadeInUp {
    from { opacity: 0; transform: translateY(40px); }
    to { opacity: 1; transform: translateY(0); }
  }
  @keyframes fadeInLeft {
    from { opacity: 0; transform: translateX(-40px); }
    to { opacity: 1; transform: translateX(0); }
  }
  @keyframes fadeInRight {
    from { opacity: 0; transform: translateX(40px); }
    to { opacity: 1; transform: translateX(0); }
  }
  @keyframes slideDown {
    from { opacity: 0; transform: translateY(-20px); }
    to { opacity: 1; transform: translateY(0); }
  }
  @keyframes shimmer {
    0% { background-position: -200% center; }
    100% { background-position: 200% center; }
  }
  @keyframes pulse-glow {
    0%, 100% { box-shadow: 0 0 20px rgba(212,175,55,0.3); }
    50% { box-shadow: 0 0 40px rgba(212,175,55,0.6); }
  }
  @keyframes float {
    0%, 100% { transform: translateY(0); }
    50% { transform: translateY(-8px); }
  }
  @keyframes countUp {
    from { opacity: 0; transform: scale(0.5); }
    to { opacity: 1; transform: scale(1); }
  }
  @keyframes marquee {
    0% { transform: translateX(0); }
    100% { transform: translateX(-50%); }
  }

  .anim-fade-up { animation: fadeInUp 1s cubic-bezier(0.25,0.46,0.45,0.94) forwards; }
  .anim-fade-left { animation: fadeInLeft 1s cubic-bezier(0.25,0.46,0.45,0.94) forwards; }
  .anim-fade-right { animation: fadeInRight 1s cubic-bezier(0.25,0.46,0.45,0.94) forwards; }
  .anim-slide-down { animation: slideDown 0.8s cubic-bezier(0.25,0.46,0.45,0.94) forwards; }

  .delay-100 { animation-delay: 0.1s; opacity: 0; animation-fill-mode: forwards; }
  .delay-200 { animation-delay: 0.2s; opacity: 0; animation-fill-mode: forwards; }
  .delay-300 { animation-delay: 0.3s; opacity: 0; animation-fill-mode: forwards; }
  .delay-400 { animation-delay: 0.4s; opacity: 0; animation-fill-mode: forwards; }
  .delay-500 { animation-delay: 0.5s; opacity: 0; animation-fill-mode: forwards; }
  .delay-600 { animation-delay: 0.6s; opacity: 0; animation-fill-mode: forwards; }
  .delay-700 { animation-delay: 0.7s; opacity: 0; animation-fill-mode: forwards; }
  .delay-800 { animation-delay: 0.8s; opacity: 0; animation-fill-mode: forwards; }

  .btn-gold-slide {
    position: relative;
    overflow: hidden;
    z-index: 1;
  }
  .btn-gold-slide::before {
    content: '';
    position: absolute;
    top: 0; left: -100%; width: 100%; height: 100%;
    background: linear-gradient(90deg, transparent, rgba(212,175,55,0.15), transparent);
    transition: left 0.6s cubic-bezier(0.25,0.46,0.45,0.94);
    z-index: -1;
  }
  .btn-gold-slide:hover::before {
    left: 100%;
  }

  .product-card:hover .product-img {
    transform: scale(1.05);
    filter: brightness(1.1);
  }
  .product-card:hover {
    transform: translateY(-4px);
    box-shadow: 0 20px 60px rgba(26,58,92,0.15);
  }

  .category-card:hover {
    transform: translateY(-6px);
    border-color: #D4AF37;
  }
  .category-card:hover .cat-icon {
    color: #D4AF37;
    transform: scale(1.1);
  }

  .brand-marquee {
    animation: marquee 30s linear infinite;
  }
  .brand-marquee:hover {
    animation-play-state: paused;
  }

  .star-gold { color: #D4AF37; }

  .search-input::placeholder {
    font-family: 'Playfair Display', serif;
    font-style: italic;
    color: #9CA3AF;
  }

  .whatsapp-float {
    animation: pulse-glow 2s ease-in-out infinite;
  }

  .hero-gradient {
    background: linear-gradient(135deg, #091A2E 0%, #1A3A5C 40%, #0F2640 70%, #091A2E 100%);
  }

  #services-hero {
    min-height: 85vh;
    max-height: 760px;
    background-color: #060f1a;
  }

  @media (max-width: 767px) {
    #services-hero {
      min-height: 70svh;
      max-height: none;
    }
  }

  #hero-bg-layers {
    isolation: isolate;
  }
  .hero-bg-layer {
    position: absolute;
    inset: 0;
    background-size: cover;
    background-repeat: no-repeat;
    background-color: #060f1a;
    opacity: 0;
    z-index: 1;
    transition: opacity 1.1s ease-in-out;
    transform: scale(1);
    will-change: opacity, transform;
    pointer-events: none;
  }
  .hero-bg-layer[data-align="left"] { background-position: 72% center; }
  .hero-bg-layer[data-align="right"] { background-position: 28% center; }
  .hero-bg-layer.active {
    opacity: 1;
    z-index: 2;
    animation: heroKenBurns 7s ease-out forwards;
  }
  @keyframes heroKenBurns {
    from { transform: scale(1); }
    to { transform: scale(1.06); }
  }

  #hero-bg-overlay {
    transition: background 0.8s ease;
  }
  #hero-bg-overlay.hero-overlay-left {
    background: linear-gradient(90deg,
      rgba(6, 15, 26, 0.88) 0%,
      rgba(6, 15, 26, 0.55) 28%,
      rgba(6, 15, 26, 0.15) 48%,
      transparent 65%);
  }
  #hero-bg-overlay.hero-overlay-right {
    background: linear-gradient(270deg,
      rgba(6, 15, 26, 0.88) 0%,
      rgba(6, 15, 26, 0.55) 28%,
      rgba(6, 15, 26, 0.15) 48%,
      transparent 65%);
  }

  #hero-content-wrap {
    width: 100%;
    display: flex;
    align-items: center;
    transition: justify-content 0.7s cubic-bezier(0.25, 0.46, 0.45, 0.94);
  }
  #hero-content-wrap.hero-content-left { justify-content: flex-start; }
  #hero-content-wrap.hero-content-right { justify-content: flex-end; }

  #hero-heading-panel {
    max-width: 32rem;
    text-shadow: 0 2px 28px rgba(0, 0, 0, 0.5);
  }
  #hero-heading-panel.hero-align-left { text-align: left; }
  #hero-heading-panel.hero-align-right { text-align: right; }
  #hero-heading-panel #hero-title { color: #fff; }
  #hero-heading-panel #hero-subtitle { color: rgba(255, 255, 255, 0.88); }

  .hero-text-swap-left {
    animation: heroTextInLeft 0.65s cubic-bezier(0.25, 0.46, 0.45, 0.94) forwards;
  }
  .hero-text-swap-right {
    animation: heroTextInRight 0.65s cubic-bezier(0.25, 0.46, 0.45, 0.94) forwards;
  }
  @keyframes heroTextInLeft {
    from { opacity: 0; transform: translateX(-28px); }
    to { opacity: 1; transform: translateX(0); }
  }
  @keyframes heroTextInRight {
    from { opacity: 0; transform: translateX(28px); }
    to { opacity: 1; transform: translateX(0); }
  }


  #hero-stats-bar {
    border-top: 1px solid rgba(192, 192, 192, 0.1);
  }
  .hero-stat-item {
    position: relative;
  }
  @media (min-width: 768px) {
    .hero-stat-item:not(:last-child)::after {
      content: '';
      position: absolute;
      right: 0;
      top: 20%;
      height: 60%;
      width: 1px;
      background: rgba(192, 192, 192, 0.12);
    }
  }

  .grid-line {
    position: absolute;
    width: 1px;
    height: 100%;
    background: rgba(192,192,192,0.08);
    top: 0;
  }

  .testimonial-card {
    border-top: 1px solid #1A3A5C;
    transition: all 0.5s cubic-bezier(0.25,0.46,0.45,0.94);
  }
  .testimonial-card:hover {
    border-top-color: #D4AF37;
    transform: translateY(-3px);
  }

  .offer-card {
    transition: all 0.5s cubic-bezier(0.25,0.46,0.45,0.94);
  }
  .offer-card:hover {
    transform: scale(1.02);
  }

  ::-webkit-scrollbar { width: 8px; }
  ::-webkit-scrollbar-track { background: #F9F8F6; }
  ::-webkit-scrollbar-thumb { background: #C0C0C0; }
  ::-webkit-scrollbar-thumb:hover { background: #1A3A5C; }

html::-webkit-scrollbar, body::-webkit-scrollbar, *::-webkit-scrollbar {
    display: none !important; width: 0 !important; height: 0 !important;
  }
  html, body, * {
    -ms-overflow-style: none !important;
    scrollbar-width: none !important;
  }

